/**
 * Tests for the Web-Fetch-pure mesh-policy edge runtime extracted from
 * x-ranger. Focuses on gate parity, option plumbing, and the Node-free
 * surface.
 */

import { describe, expect, it } from '@a0n/gnosis/test';
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import {
  auditPolicy,
  buildLinkFromBinding,
  checkRequest,
  describeMeshPolicyPosture,
  pathMatchesPort,
  pathMatchesPrefix,
  sanitizeReason,
  wrapWithMeshPolicy,
  type GateDecisionEvent,
  type InnerFetch,
  type MeshPolicyConfig,
  type MeshServiceBinding,
} from '../mesh-policy-edge';
import { createMesh } from '../mesh-policy';

// ─── Helper inner-fetch ─────────────────────────────────────────────

const okInner: InnerFetch = () =>
  new Response('ok', { status: 200, headers: { 'content-type': 'text/plain' } });

const emptyEnv = {} as Record<string, unknown>;
const emptyCtx: unknown = undefined;

describe('mesh-policy-edge', () => {
  describe('Node-free surface', () => {
    it('source file has no node: imports, no process., no console.', () => {
      // Read the edge source and assert it is free of Node-specific
      // primitives. The rule is stricter than the final runtime
      // requirement: even comments mentioning `process.` or `console.`
      // would trip this, which is the correct conservative signal.
      const url = new URL('../mesh-policy-edge.ts', import.meta.url);
      const path = fileURLToPath(url);
      const source = readFileSync(path, 'utf8');
      const forbidden = [
        /from\s+['"]node:/,
        /require\(\s*['"]node:/,
        /\bprocess\./,
        /\bconsole\./,
        /\bBuffer\./,
      ];
      for (const pattern of forbidden) {
        const m = source.match(pattern);
        expect(m).toBeNull();
      }
    });
  });

  describe('pathMatchesPrefix / pathMatchesPort', () => {
    it('matches exact and proper-segment prefixes', () => {
      expect(pathMatchesPrefix('/api', '/api')).toBe(true);
      expect(pathMatchesPrefix('/api/v1', '/api')).toBe(true);
      expect(pathMatchesPort('/api/', '/api')).toBe(true);
    });

    it('rejects non-segment prefix matches', () => {
      expect(pathMatchesPrefix('/apiary', '/api')).toBe(false);
      expect(pathMatchesPrefix('/api-keys', '/api')).toBe(false);
      expect(pathMatchesPrefix('/api.json', '/api')).toBe(false);
    });

    it('normalizes trailing slash on prefix', () => {
      expect(pathMatchesPrefix('/api', '/api/')).toBe(true);
      expect(pathMatchesPrefix('/api/v1', '/api/')).toBe(true);
    });
  });

  describe('sanitizeReason', () => {
    it('strips C0 controls and caps at 200 chars', () => {
      expect(sanitizeReason('abc\x00def')).toBe('abc def');
      expect(sanitizeReason('')).toBe('(no reason)');
      const long = 'x'.repeat(250);
      const out = sanitizeReason(long);
      expect(out.endsWith('...')).toBe(true);
      expect(out.length).toBe(203);
    });
  });

  describe('wrapWithMeshPolicy — gate decisions', () => {
    const policy: MeshPolicyConfig = {
      ports: [
        { path: '/api', methods: ['GET', 'POST'] },
        { path: '/health' },
      ],
      overlays: [{ pathPrefix: '/api/admin', reason: 'restricted' }],
      requireAuthHeaderPresent: true,
    };

    it('returns 404 for non-whitelisted paths', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/nope'),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(404);
      // RFC 9110 §13.2: denial responses must not be cached by
      // intermediaries (the 404 body echoes the requested path).
      expect(res.headers.get('cache-control')).toBe('no-store');
    });

    it('returns 403 for overlay-blocked paths', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/api/admin/reset', {
          headers: { authorization: 'Bearer zzz' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(403);
      const body = await res.text();
      expect(body.includes('overlay-blocked')).toBe(true);
      // Overlay `reason` may carry operator-specific context; never
      // cache it in a shared proxy.
      expect(res.headers.get('cache-control')).toBe('no-store');
    });

    it('returns 405 when method not in port allowlist', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/api', {
          method: 'DELETE',
          headers: { authorization: 'Bearer zzz' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(405);
      expect(res.headers.get('Allow')).toBe('GET, POST');
      expect(res.headers.get('cache-control')).toBe('no-store');
    });

    it('returns 401 when auth required but header absent', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/api'),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(401);
      // RFC 9110 §11.6.1: the WWW-Authenticate challenge MUST name the
      // auth scheme and SHOULD include a realm so the client knows
      // which protection space it is entering.
      expect(res.headers.get('WWW-Authenticate')).toBe(
        'Bearer realm="mesh-policy"',
      );
      expect(res.headers.get('cache-control')).toBe('no-store');
    });

    it('delegates to innerFetch when all gates pass', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/api', {
          headers: { authorization: 'Bearer zzz' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(200);
      expect(await res.text()).toBe('ok');
    });

    it('OPTIONS returns 200 with Allow header', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/api', { method: 'OPTIONS' }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(200);
      const allow = res.headers.get('Allow');
      expect(allow).not.toBeNull();
      expect(allow!.includes('OPTIONS')).toBe(true);
      expect(allow!.includes('GET')).toBe(true);
    });

    it('HEAD is auto-allowed when GET is in method set', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/api', {
          method: 'HEAD',
          headers: { authorization: 'Bearer zzz' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(200);
    });
  });

  describe('wrapWithMeshPolicy — options plumbing', () => {
    const policy: MeshPolicyConfig = {
      ports: [{ path: '/api' }],
      overlays: [{ pathPrefix: '/api/secret', reason: 'locked' }],
      mode: 'audit',
    };

    it('audit callback fires in audit mode; delegates regardless', async () => {
      const msgs: string[] = [];
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        audit: (m) => msgs.push(m),
      });
      const res = await wrapped(
        new Request('https://x.test/nope'),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(200); // audit delegates through
      expect(msgs.length).toBe(1);
      expect(msgs[0]!.includes('[mesh-policy-edge:audit]')).toBe(true);
      expect(msgs[0]!.includes('gate=path')).toBe(true);
    });

    it('silent in enforce mode when no audit callback supplied', async () => {
      const enforcePolicy: MeshPolicyConfig = {
        ports: [{ path: '/api' }],
      };
      const wrapped = wrapWithMeshPolicy(okInner, enforcePolicy);
      const res = await wrapped(
        new Request('https://x.test/nope'),
        emptyEnv,
        emptyCtx,
      );
      // Silent -- no throw, no console -- just the 404.
      expect(res.status).toBe(404);
    });

    it('shadow mode uses shadow log prefix', async () => {
      const shadowPolicy: MeshPolicyConfig = {
        ports: [{ path: '/api' }],
        mode: 'shadow',
      };
      const msgs: string[] = [];
      const wrapped = wrapWithMeshPolicy(okInner, shadowPolicy, {
        audit: (m) => msgs.push(m),
      });
      await wrapped(new Request('https://x.test/nope'), emptyEnv, emptyCtx);
      expect(msgs[0]!.includes('[mesh-policy-edge:shadow]')).toBe(true);
    });
  });

  describe('wrapWithMeshPolicy — overlayHandler hook', () => {
    const policy: MeshPolicyConfig = {
      ports: [{ path: '/api' }],
      overlays: [
        { pathPrefix: '/api/trap', reason: 'honey', honeypit: true },
      ],
    };

    it('uses custom Response when overlayHandler returns one', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        overlayHandler: () => new Response('trapped', { status: 418 }),
      });
      const res = await wrapped(
        new Request('https://x.test/api/trap/foo'),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(418);
      expect(await res.text()).toBe('trapped');
    });

    it('falls through to 403 when overlayHandler returns null', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        overlayHandler: () => null,
      });
      const res = await wrapped(
        new Request('https://x.test/api/trap/foo'),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(403);
    });

    it('invokes overlayHandler with the matched overlay spec', async () => {
      let captured: string | undefined;
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        overlayHandler: (overlay) => {
          captured = overlay.pathPrefix;
          return null;
        },
      });
      await wrapped(
        new Request('https://x.test/api/trap/foo'),
        emptyEnv,
        emptyCtx,
      );
      expect(captured).toBe('/api/trap');
    });
  });

  describe('checkRequest', () => {
    it('returns delegate for undefined policy', () => {
      const r = checkRequest(undefined, '/anything');
      expect(r.gate).toBe('delegate');
      expect(r.status).toBe(200);
    });

    it('mirrors the wrap gate order', () => {
      const policy: MeshPolicyConfig = {
        ports: [{ path: '/api', methods: ['GET'] }],
        overlays: [{ pathPrefix: '/api/secret' }],
        requireAuthHeaderPresent: true,
      };
      expect(checkRequest(policy, '/api/secret/x').gate).toBe('overlay');
      expect(checkRequest(policy, '/nope').gate).toBe('path');
      expect(checkRequest(policy, '/api', 'POST').gate).toBe('method');
      expect(checkRequest(policy, '/api', 'GET', false).gate).toBe('auth');
      expect(checkRequest(policy, '/api', 'GET', true).gate).toBe('delegate');
    });
  });

  describe('auditPolicy', () => {
    it('handles undefined policy', () => {
      const r = auditPolicy(undefined);
      expect(r.policyPresent).toBe(false);
      expect(r.findings.length).toBe(0);
      expect(r.bypassReductions.zenonicStepsUntilUnderflow).toBe('infinite');
    });

    it('warns on empty port list', () => {
      const r = auditPolicy({ ports: [] });
      expect(r.policyPresent).toBe(true);
      const codes = r.findings.map((f) => f.code);
      expect(codes.includes('EMPTY_PORTS')).toBe(true);
    });

    it('flags invalid port path and dead overlays', () => {
      const r = auditPolicy({
        ports: [{ path: 'no-slash' }],
        overlays: [{ pathPrefix: '/orphan' }],
      });
      const codes = r.findings.map((f) => f.code);
      expect(codes.includes('PORT_PATH_INVALID')).toBe(true);
      expect(codes.includes('OVERLAY_DEAD')).toBe(true);
    });

    it('flags TOTAL_MESH_COLLAPSE when overlays cover all ports', () => {
      const r = auditPolicy({
        ports: [{ path: '/api' }],
        overlays: [{ pathPrefix: '/api' }],
      });
      const codes = r.findings.map((f) => f.code);
      expect(codes.includes('TOTAL_MESH_COLLAPSE')).toBe(true);
    });
  });

  describe('describeMeshPolicyPosture', () => {
    it('returns zeroed report for undefined policy', () => {
      const r = describeMeshPolicyPosture(undefined);
      expect(r.totalPorts).toBe(0);
      expect(r.reachablePorts.length).toBe(0);
      expect(r.blockedPaths.length).toBe(0);
    });

    it('lists reachable and blocked paths', () => {
      const r = describeMeshPolicyPosture({
        ports: [{ path: '/a' }, { path: '/b' }],
        overlays: [{ pathPrefix: '/a' }],
      });
      expect(r.totalPorts).toBe(2);
      expect(r.reachablePorts).toEqual(['/b']);
      expect(r.blockedPaths).toEqual(['/a']);
      expect(r.netReachablePortCount).toBe(1);
    });
  });

  describe('pluggable auth verifier', () => {
    const policy: MeshPolicyConfig = {
      ports: [{ path: '/api' }],
      requireAuthHeaderPresent: true,
    };

    it('delegates when verifier returns true', async () => {
      let calls = 0;
      const verifier = async (): Promise<boolean> => {
        calls += 1;
        return true;
      };
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        authVerifier: verifier,
      });
      const res = await wrapped(
        new Request('https://x.test/api', {
          headers: { authorization: 'Bearer good' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(200);
      expect(await res.text()).toBe('ok');
      expect(calls).toBe(1);
    });

    it('returns 401 when verifier returns false', async () => {
      let calls = 0;
      const verifier = async (): Promise<boolean> => {
        calls += 1;
        return false;
      };
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        authVerifier: verifier,
      });
      const res = await wrapped(
        new Request('https://x.test/api', {
          headers: { authorization: 'Bearer bad' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(401);
      expect(res.headers.get('WWW-Authenticate')).toBe(
        'Bearer realm="mesh-policy"',
      );
      expect(res.headers.get('cache-control')).toBe('no-store');
      expect(calls).toBe(1);
    });

    it('returns 401 when verifier throws', async () => {
      let calls = 0;
      const verifier = async (): Promise<boolean> => {
        calls += 1;
        throw new Error('fake');
      };
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        authVerifier: verifier,
      });
      const res = await wrapped(
        new Request('https://x.test/api', {
          headers: { authorization: 'Bearer boom' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(401);
      expect(res.headers.get('WWW-Authenticate')).toBe(
        'Bearer realm="mesh-policy"',
      );
      expect(calls).toBe(1);
      // Fail-closed: verifier error must NEVER leak into body.
      const body = await res.text();
      expect(body.includes('fake')).toBe(false);
    });

    it('calls audit callback with error message when verifier throws', async () => {
      const verifier = async (): Promise<boolean> => {
        throw new Error('kaboom');
      };
      const msgs: string[] = [];
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        authVerifier: verifier,
        audit: (m) => msgs.push(m),
      });
      const res = await wrapped(
        new Request('https://x.test/api', {
          headers: { authorization: 'Bearer boom' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(401);
      // At least one audit message should describe the verifier throw.
      const threwMsg = msgs.find((m) => m.includes('authVerifier threw'));
      expect(threwMsg).not.toBeUndefined();
      expect(threwMsg!.includes('kaboom')).toBe(true);
    });

    it('falls back to presence-only when verifier is not provided', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      // Header present, no verifier → presence-only → delegate.
      const ok = await wrapped(
        new Request('https://x.test/api', {
          headers: { authorization: 'Bearer anything' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(ok.status).toBe(200);
      // Header absent → 401 as before.
      const denied = await wrapped(
        new Request('https://x.test/api'),
        emptyEnv,
        emptyCtx,
      );
      expect(denied.status).toBe(401);
    });

    it('never calls verifier when header is missing (still 401)', async () => {
      let calls = 0;
      const verifier = async (): Promise<boolean> => {
        calls += 1;
        return true;
      };
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        authVerifier: verifier,
      });
      const res = await wrapped(
        new Request('https://x.test/api'),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(401);
      expect(calls).toBe(0);
    });

    it('never calls verifier when requireAuth is false', async () => {
      const openPolicy: MeshPolicyConfig = {
        ports: [{ path: '/api' }],
      };
      let calls = 0;
      const verifier = async (): Promise<boolean> => {
        calls += 1;
        return true;
      };
      const wrapped = wrapWithMeshPolicy(okInner, openPolicy, {
        authVerifier: verifier,
      });
      const res = await wrapped(
        new Request('https://x.test/api', {
          headers: { authorization: 'Bearer anything' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(200);
      expect(calls).toBe(0);
    });

    it('verifier receives the Request and the full authHeader value', async () => {
      let seenHeader: string | undefined;
      let seenUrl: string | undefined;
      const verifier = async (
        request: Request,
        authHeader: string,
      ): Promise<boolean> => {
        seenHeader = authHeader;
        seenUrl = request.url;
        return true;
      };
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        authVerifier: verifier,
      });
      const res = await wrapped(
        new Request('https://x.test/api', {
          headers: { authorization: 'Bearer eyJ.payload.sig' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(200);
      expect(seenHeader).toBe('Bearer eyJ.payload.sig');
      expect(seenUrl).toBe('https://x.test/api');
    });
  });

  describe('linked-service helpers', () => {
    it('buildLinkFromBinding returns null when mesh metadata absent', () => {
      const binding: MeshServiceBinding = {
        binding: 'SVC',
        service: 'other',
      };
      const link = buildLinkFromBinding(
        binding,
        createMesh(2, 2),
        createMesh(2, 2),
      );
      expect(link).toBeNull();
    });

    it('buildLinkFromBinding rejects out-of-range indices', () => {
      const binding: MeshServiceBinding = {
        binding: 'SVC',
        service: 'other',
        mesh: { sourcePortIdx: 5, destPortIdx: 0, inheritOverlays: false },
      };
      const link = buildLinkFromBinding(
        binding,
        createMesh(2, 2),
        createMesh(2, 2),
      );
      expect(link).toBeNull();
    });

    it('buildLinkFromBinding constructs a formal Link', () => {
      const binding: MeshServiceBinding = {
        binding: 'SVC',
        service: 'other',
        mesh: { sourcePortIdx: 0, destPortIdx: 1, inheritOverlays: false },
      };
      const link = buildLinkFromBinding(
        binding,
        createMesh(2, 2),
        createMesh(2, 2),
      );
      expect(link).not.toBeNull();
      expect(link!.sourcePortIdx).toBe(0);
      expect(link!.destPortIdx).toBe(1);
    });
  });

  describe('onGateDecision + content negotiation', () => {
    const policy: MeshPolicyConfig = {
      ports: [
        { path: '/api', methods: ['GET', 'POST'] },
        { path: '/health' },
      ],
      overlays: [{ pathPrefix: '/api/admin', reason: 'restricted' }],
      requireAuthHeaderPresent: true,
    };

    // ─── onGateDecision firing at each gate ─────────────────────────

    it('fires onGateDecision at overlay gate deny', async () => {
      const events: GateDecisionEvent[] = [];
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        onGateDecision: (e) => events.push(e),
      });
      const res = await wrapped(
        new Request('https://x.test/api/admin/reset', {
          headers: { authorization: 'Bearer zzz' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(403);
      expect(events.length).toBe(1);
      expect(events[0]!.gate).toBe('overlay');
      expect(events[0]!.decision).toBe('deny');
      expect(events[0]!.status).toBe(403);
    });

    it('fires onGateDecision at path gate deny', async () => {
      const events: GateDecisionEvent[] = [];
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        onGateDecision: (e) => events.push(e),
      });
      const res = await wrapped(
        new Request('https://x.test/nope'),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(404);
      expect(events.length).toBe(1);
      expect(events[0]!.gate).toBe('path');
      expect(events[0]!.decision).toBe('deny');
      expect(events[0]!.status).toBe(404);
    });

    it('fires onGateDecision at method gate deny', async () => {
      const events: GateDecisionEvent[] = [];
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        onGateDecision: (e) => events.push(e),
      });
      const res = await wrapped(
        new Request('https://x.test/api', {
          method: 'DELETE',
          headers: { authorization: 'Bearer zzz' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(405);
      expect(events.length).toBe(1);
      expect(events[0]!.gate).toBe('method');
      expect(events[0]!.decision).toBe('deny');
      expect(events[0]!.status).toBe(405);
    });

    it('fires onGateDecision at auth gate deny', async () => {
      const events: GateDecisionEvent[] = [];
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        onGateDecision: (e) => events.push(e),
      });
      const res = await wrapped(
        new Request('https://x.test/api'),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(401);
      expect(events.length).toBe(1);
      expect(events[0]!.gate).toBe('auth');
      expect(events[0]!.decision).toBe('deny');
      expect(events[0]!.status).toBe(401);
    });

    it('fires onGateDecision at delegate (allow)', async () => {
      const events: GateDecisionEvent[] = [];
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        onGateDecision: (e) => events.push(e),
      });
      const res = await wrapped(
        new Request('https://x.test/api', {
          headers: { authorization: 'Bearer zzz' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(200);
      expect(events.length).toBe(1);
      expect(events[0]!.gate).toBe('delegate');
      expect(events[0]!.decision).toBe('allow');
      expect(events[0]!.status).toBe(200);
      expect(events[0]!.theorem).toBe('fullPortListEqualsOpenMesh');
    });

    // ─── event shape ────────────────────────────────────────────────

    it('event carries gate, decision, status, path, method, theorem, timestampMs', async () => {
      const events: GateDecisionEvent[] = [];
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        onGateDecision: (e) => events.push(e),
      });
      const before = Date.now();
      await wrapped(new Request('https://x.test/nope'), emptyEnv, emptyCtx);
      const after = Date.now();
      const e = events[0]!;
      expect(e.gate).toBe('path');
      expect(e.decision).toBe('deny');
      expect(e.status).toBe(404);
      expect(e.path).toBe('/nope');
      expect(e.method).toBe('GET');
      expect(e.theorem).toBe('deploymentShapesToContainer');
      expect(typeof e.timestampMs).toBe('number');
      expect(e.timestampMs >= before).toBe(true);
      expect(e.timestampMs <= after).toBe(true);
    });

    it('event carries matchedOverlayPrefix on overlay deny', async () => {
      const events: GateDecisionEvent[] = [];
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        onGateDecision: (e) => events.push(e),
      });
      await wrapped(
        new Request('https://x.test/api/admin/reset', {
          headers: { authorization: 'Bearer zzz' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(events[0]!.matchedOverlayPrefix).toBe('/api/admin');
      expect(events[0]!.theorem).toBe('portOverlayCancelsWithinPorts');
    });

    it('event carries methodsAllowed on 405', async () => {
      const events: GateDecisionEvent[] = [];
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        onGateDecision: (e) => events.push(e),
      });
      await wrapped(
        new Request('https://x.test/api', {
          method: 'DELETE',
          headers: { authorization: 'Bearer zzz' },
        }),
        emptyEnv,
        emptyCtx,
      );
      const e = events[0]!;
      expect(e.methodsAllowed).not.toBeUndefined();
      expect(e.methodsAllowed!.includes('GET')).toBe(true);
      expect(e.methodsAllowed!.includes('POST')).toBe(true);
    });

    it('event carries authHeaderPresent on auth gate events', async () => {
      const events: GateDecisionEvent[] = [];
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        onGateDecision: (e) => events.push(e),
      });
      await wrapped(new Request('https://x.test/api'), emptyEnv, emptyCtx);
      expect(events[0]!.gate).toBe('auth');
      expect(events[0]!.authHeaderPresent).toBe(false);

      const events2: GateDecisionEvent[] = [];
      const wrapped2 = wrapWithMeshPolicy(okInner, policy, {
        onGateDecision: (e) => events2.push(e),
        authVerifier: async () => false,
      });
      await wrapped2(
        new Request('https://x.test/api', {
          headers: { authorization: 'Bearer x' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(events2[0]!.gate).toBe('auth');
      expect(events2[0]!.authHeaderPresent).toBe(true);
    });

    // ─── error swallowing ───────────────────────────────────────────

    it('onGateDecision throwing does not affect response', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy, {
        onGateDecision: () => {
          throw new Error('observer boom');
        },
      });
      // Deny path.
      const res404 = await wrapped(
        new Request('https://x.test/nope'),
        emptyEnv,
        emptyCtx,
      );
      expect(res404.status).toBe(404);
      // Allow path.
      const res200 = await wrapped(
        new Request('https://x.test/api', {
          headers: { authorization: 'Bearer z' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res200.status).toBe(200);
    });

    // ─── content negotiation ────────────────────────────────────────

    it('returns text body when Accept is not application/json', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/nope', {
          headers: { accept: 'text/html' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(404);
      expect(res.headers.get('content-type')).toBe('text/plain; charset=utf-8');
      const body = await res.text();
      // The existing text format stays unchanged.
      expect(body.includes('path not on port whitelist')).toBe(true);
    });

    it('returns JSON body when Accept: application/json', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/nope', {
          headers: { accept: 'application/json' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(404);
      expect(res.headers.get('content-type')).toBe(
        'application/json; charset=utf-8',
      );
      const body = (await res.json()) as Record<string, unknown>;
      expect(body['error']).toBe('path-not-whitelisted');
    });

    it('JSON body carries error, status, path, method, theorem', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/nope', {
          method: 'POST',
          headers: { accept: 'application/json' },
        }),
        emptyEnv,
        emptyCtx,
      );
      const body = (await res.json()) as Record<string, unknown>;
      expect(body['error']).toBe('path-not-whitelisted');
      expect(body['status']).toBe(404);
      expect(body['path']).toBe('/nope');
      expect(body['method']).toBe('POST');
      expect(body['theorem']).toBe('deploymentShapesToContainer');
    });

    it('JSON body carries reason + matchedOverlay on 403', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/api/admin/reset', {
          headers: {
            authorization: 'Bearer zzz',
            accept: 'application/json',
          },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(403);
      const body = (await res.json()) as Record<string, unknown>;
      expect(body['error']).toBe('overlay-blocked');
      expect(body['matchedOverlay']).toBe('/api/admin');
      expect(body['reason']).toBe('restricted');
      expect(body['theorem']).toBe('portOverlayCancelsWithinPorts');
    });

    it('JSON body carries methodsAllowed on 405', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/api', {
          method: 'DELETE',
          headers: {
            authorization: 'Bearer zzz',
            accept: 'application/json',
          },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(405);
      const body = (await res.json()) as Record<string, unknown>;
      expect(body['error']).toBe('method-not-allowed');
      const methods = body['methodsAllowed'] as string[];
      expect(methods.includes('GET')).toBe(true);
      expect(methods.includes('POST')).toBe(true);
    });

    it('JSON content-type header is application/json; charset=utf-8', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/nope', {
          headers: { accept: 'application/json' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.headers.get('content-type')).toBe(
        'application/json; charset=utf-8',
      );
    });

    it('text content-type header stays text/plain; charset=utf-8', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/nope'),
        emptyEnv,
        emptyCtx,
      );
      expect(res.headers.get('content-type')).toBe('text/plain; charset=utf-8');
    });

    // ─── header preservation on JSON 4xx ─────────────────────────────

    it('Cache-Control: no-store still present on JSON 4xx', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/nope', {
          headers: { accept: 'application/json' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.headers.get('cache-control')).toBe('no-store');
    });

    it('Allow header still present on JSON 405', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/api', {
          method: 'DELETE',
          headers: {
            authorization: 'Bearer zzz',
            accept: 'application/json',
          },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(405);
      expect(res.headers.get('Allow')).toBe('GET, POST');
    });

    it('WWW-Authenticate still present on JSON 401', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/api', {
          headers: { accept: 'application/json' },
        }),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(401);
      expect(res.headers.get('WWW-Authenticate')).toBe(
        'Bearer realm="mesh-policy"',
      );
    });

    // ─── backward compat ───────────────────────────────────────────

    it('absence of onGateDecision preserves existing behavior', async () => {
      const wrapped = wrapWithMeshPolicy(okInner, policy);
      const res = await wrapped(
        new Request('https://x.test/nope'),
        emptyEnv,
        emptyCtx,
      );
      expect(res.status).toBe(404);
      expect(res.headers.get('content-type')).toBe('text/plain; charset=utf-8');
    });
  });
});
